@app.route('/login')
def login():
    redirect_uri = url_for('authorize', _external=True)
    google_auth_url = (
        'https://accounts.google.com/o/oauth2/v2/auth?'
        + 'scope=openid%20email&'
        + 'redirect_uri={redirect_uri}&'
        + 'response_type=code&'
        + 'client_id={client_id}').format(redirect_uri=redirect_uri, client_id=app.config['OAUTH2_CLIENT_ID'])
    return redirect(google_auth_url)

@app.route('/callback')
def authorize():
    code = request.args.get('code', '')
    
    # Check if the redirect URI is valid for subdomains
    configured_redirect_uri = app.config['REDIRECT_URI']
    incoming_redirect_uri = url_for('authorize', _external=True)
    domain = urlparse(configured_redirect_uri).netloc
    
    if domain not in incoming_redirect_uri:
        return "Invalid redirect URI.", 403
        
    data = {
        'code': code,
        'client_id': app.config['OAUTH2_CLIENT_ID'],
        'client_secret': app.config['OAUTH2_CLIENT_SECRET'],
        'redirect_uri': incoming_redirect_uri,
        'grant_type': 'authorization_code'
    }
    
    r = requests.post('https://oauth2.googleapis.com/token', data=data)
    token_info = r.json()
    
    if 'error' in token_info:
        return redirect(url_for('login'))
        
    session['access_token'] = token_info['access_token']
    userinfo_endpoint = "https://www.googleapis.com/oauth2/v1/userinfo"
    
    header = {"Authorization": "Bearer {}".format(session['access_token'])}
    r = requests.get(userinfo_endpoint, headers=header)
    userinfo = r.json()
    session['userinfo'] = userinfo
    
    return redirect(url_for('index'))